package controllers

import javax.inject._
import play.api.mvc._
import scala.io.Source
import java.nio.file.{Files, Path, Paths}
import java.nio.charset.StandardCharsets

@Singleton
class UserFilesController @Inject() (cc: ControllerComponents) extends AbstractController(cc) {

  private val UploadsDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def serve(filename: String): Action[AnyContent] = Action {
    val requested: Path = UploadsDir.resolve(filename).normalize()

    if (!requested.startsWith(UploadsDir)) {
      Forbidden("Invalid path")
    } else if (!Files.exists(requested) || !Files.isRegularFile(requested)) {
      NotFound("File not found")
    } else {
      val src = Source.fromFile(requested.toFile)(StandardCharsets.UTF_8)
      try {
        Ok(src.mkString).as("application/octet-stream")
      } finally {
        src.close()
      }
    }
  }
}